import json
from typing import Any, Dict, List

def sum_second_column(json_data: str) -> Dict[str, Any]:
    """
    解析JSON格式的CSV数据并计算第二列的数值总和。

    Args:
        json_data: JSON格式的字符串，表示一个对象数组，每个对象代表一行数据。

    Returns:
        包含'sum'和'rows'键的字典。
        - sum: 第二列数值的总和（非数值行忽略）。
        - rows: 有效数值行的数量。
    """
    try:
        data = json.loads(json_data)
    except json.JSONDecodeError:
        return {"sum": 0, "rows": 0}

    if not isinstance(data, list):
        return {"sum": 0, "rows": 0}

    total_sum = 0
    valid_rows = 0

    for row in data:
        if not isinstance(row, dict):
            continue

        # 获取第二列的值（假设第二列是字典中的第二个键值对）
        # 由于JSON对象是无序的，我们需要按顺序获取第二个键
        # 但规约示例中使用了'col2'作为第二列，所以我们直接使用'col2'键
        # 如果不存在'col2'键，则跳过该行
        if 'col2' not in row:
            continue

        value = row['col2']

        # 检查值是否为数值类型（int或float）
        if isinstance(value, (int, float)):
            total_sum += value
            valid_rows += 1
        # 如果值是字符串，尝试转换为数值
        elif isinstance(value, str):
            try:
                num = float(value)
                total_sum += num
                valid_rows += 1
            except ValueError:
                continue
        # 其他类型（如None、布尔值等）忽略
        else:
            continue

    return {"sum": total_sum, "rows": valid_rows}
